parameters.jsCode:
// Filter transcripts from last 7 days that match sales keywords
const response = $input.first().json;
const config = $('2. Set — Config Values').item.json;

// Extract transcripts array from GraphQL response
const transcripts = response.data?.transcripts || [];

if (transcripts.length === 0) {
  return [{
    json: {
      hasTranscripts: false,
      message: 'No transcripts found in Fireflies account.',
      weekStart: config.weekStart,
      weekEnd: config.weekEnd,
      slackChannel: config.slackChannel,
      companyName: config.companyName
    }
  }];
}

// Filter to last 7 days
const sevenDaysAgo = config.sevenDaysAgoMs;
const keywords = config.salesKeywords.toLowerCase().split(',').map(k => k.trim());

const recentSalesCalls = transcripts.filter(t => {
  const transcriptDate = t.date || 0;
  return transcriptDate >= sevenDaysAgo;
});

if (recentSalesCalls.length === 0) {
  return [{
    json: {
      hasTranscripts: false,
      message: `No transcripts found in the last 7 days (${config.weekStart} to ${config.weekEnd}).`,
      weekStart: config.weekStart,
      weekEnd: config.weekEnd,
      slackChannel: config.slackChannel,
      companyName: config.companyName
    }
  }];
}

// Return one item per transcript for the loop
return recentSalesCalls.map(t => ({
  json: {
    hasTranscripts: true,
    transcriptId: t.id,
    transcriptTitle: t.title || 'Untitled Meeting',
    transcriptDate: t.date
      ? new Date(t.date).toISOString().split('T')[0]
      : 'Unknown Date',
    durationMinutes: Math.round((t.duration || 0) / 60),
    participants: (t.participants || []).join(', ') || 'Unknown',
    firefliesApiKey: config.firefliesApiKey,
    sheetId: config.sheetId,
    sheetName: config.sheetName,
    slackChannel: config.slackChannel,
    companyName: config.companyName,
    weekStart: config.weekStart,
    weekEnd: config.weekEnd,
    totalCallsThisWeek: recentSalesCalls.length
  }
}));

parameters.jsonBody:
={
  "query": "query GetTranscriptDetails($id: String!) { transcript(id: $id) { id title date duration participants transcript_url sentences { speaker_name text ai_filters { task pricing metric question date_and_time sentiment } } summary { keywords action_items overview } analytics { sentiments { positive_pct neutral_pct negative_pct } } } }",
  "variables": {
    "id": "{{ $json.transcriptId }}"
  }
}

parameters.jsCode:
// Extract and prepare transcript data for AI analysis
const response = $input.first().json;
const prevData = $('4. Code — Filter Last 7 Days').item.json;

// Extract transcript from GraphQL response
const transcript = response.data?.transcript || {};

// Build full text from sentences — limit to 4000 chars for GPT
const sentences = transcript.sentences || [];
let fullText = '';
let pricingSentences = [];
let questionSentences = [];
let taskSentences = [];

sentences.forEach(s => {
  const speaker = s.speaker_name || 'Unknown';
  const text = s.text || '';
  fullText += `${speaker}: ${text}\n`;

  if (s.ai_filters?.pricing) pricingSentences.push(`${speaker}: ${text}`);
  if (s.ai_filters?.question) questionSentences.push(`${speaker}: ${text}`);
  if (s.ai_filters?.task) taskSentences.push(`${speaker}: ${text}`);
});

const truncatedText = fullText.substring(0, 4000);

const summary = transcript.summary || {};
const keywords = (summary.keywords || []).slice(0, 10).join(', ');
const actionItems = (summary.action_items || []).slice(0, 5).join(' | ');
const overview = summary.overview || 'No overview available';

const sentiments = transcript.analytics?.sentiments || {};
const positivePct = Math.round(sentiments.positive_pct || 0);
const neutralPct = Math.round(sentiments.neutral_pct || 0);
const negativePct = Math.round(sentiments.negative_pct || 0);

let overallSentiment = 'Neutral';
if (positivePct > 60) overallSentiment = 'Positive';
else if (negativePct > 40) overallSentiment = 'Negative';
else if (positivePct > negativePct) overallSentiment = 'Mostly Positive';
else overallSentiment = 'Mixed';

return [{
  json: {
    transcriptId: transcript.id || prevData.transcriptId,
    transcriptTitle: transcript.title || prevData.transcriptTitle,
    transcriptDate: prevData.transcriptDate,
    durationMinutes: Math.round((transcript.duration || 0) / 60) || prevData.durationMinutes,
    participants: (transcript.participants || []).join(', ') || prevData.participants,
    transcriptUrl: transcript.transcript_url || 'Not available',
    truncatedText,
    pricingSentences: pricingSentences.slice(0, 5).join(' | ') || 'None detected',
    questionSentences: questionSentences.slice(0, 5).join(' | ') || 'None detected',
    taskSentences: taskSentences.slice(0, 5).join(' | ') || 'None detected',
    keywords,
    actionItems,
    overview,
    overallSentiment,
    positivePct,
    negativePct,
    firefliesApiKey: prevData.firefliesApiKey,
    sheetId: prevData.sheetId,
    sheetName: prevData.sheetName,
    slackChannel: prevData.slackChannel,
    companyName: prevData.companyName,
    weekStart: prevData.weekStart,
    weekEnd: prevData.weekEnd,
    totalCallsThisWeek: prevData.totalCallsThisWeek
  }
}];

parameters.text:
=You are a sales intelligence analyst at {{ $json.companyName }}.

Analyze this sales call transcript and extract structured intelligence.

CALL DETAILS:
Title: {{ $json.transcriptTitle }}
Date: {{ $json.transcriptDate }}
Duration: {{ $json.durationMinutes }} minutes
Participants: {{ $json.participants }}
Overall Sentiment: {{ $json.overallSentiment }} (Positive: {{ $json.positivePct }}%, Negative: {{ $json.negativePct }}%)

FIREFLIES AI-DETECTED PRICING SENTENCES:
{{ $json.pricingSentences }}

FIREFLIES AI-DETECTED QUESTIONS:
{{ $json.questionSentences }}

FIREFLIES KEYWORDS: {{ $json.keywords }}

FIREFLIES OVERVIEW: {{ $json.overview }}

TRANSCRIPT EXCERPT:
{{ $json.truncatedText }}

Return ONLY a valid JSON object with exactly these 6 fields. No extra text. No markdown. No backticks.

pricingMentions — List the specific prices, packages, budgets, or cost discussions mentioned. If none, write: No pricing discussed. Keep under 80 words.

objections — List every objection or concern raised by the prospect or client. Each objection on a new line starting with a dash. If none found, write: No objections detected.

buyingSignals — List every positive signal showing the prospect is interested or moving toward a decision. Examples: asked about timeline, requested proposal, mentioned budget availability. If none, write: No buying signals detected.

competitorMentions — List any competitor names or alternative products mentioned. If none, write: No competitors mentioned.

keyTakeaway — One clear sentence summarizing what happened in this call and what the next step should be. Under 25 words.

recommendedAction — One specific action the sales rep should take within 48 hours based on this call. Be concrete and direct. Under 20 words.

