parameters.jsCode:
// Aggregate all analyzed calls into weekly summary for Slack
const allItems = $input.all();

if (!allItems || allItems.length === 0) {
  return [{
    json: {
      slackMessage: 'No sales calls analyzed this week.',
      slackChannel: '#sales-team'
    }
  }];
}

const config = allItems[0].json;
const totalCalls = allItems.length;

const allObjections = [];
const allBuyingSignals = [];
const allCompetitors = [];
const callSummaries = [];
let positiveCallCount = 0;
let negativeCallCount = 0;

allItems.forEach(item => {
  const d = item.json;

  if (d.overallSentiment === 'Positive' || d.overallSentiment === 'Mostly Positive') positiveCallCount++;
  if (d.overallSentiment === 'Negative') negativeCallCount++;

  if (d.objections && !d.objections.toLowerCase().includes('no objection')) {
    allObjections.push(`[${d.callTitle}]: ${d.objections.substring(0, 100)}`);
  }

  if (d.buyingSignals && !d.buyingSignals.toLowerCase().includes('no buying')) {
    allBuyingSignals.push(`[${d.callTitle}]: ${d.buyingSignals.substring(0, 100)}`);
  }

  if (d.competitorMentions && !d.competitorMentions.toLowerCase().includes('no competitor')) {
    allCompetitors.push(d.competitorMentions.substring(0, 60));
  }

  callSummaries.push(`${d.callDate} | ${d.callTitle} | ${d.durationMinutes}min | ${d.overallSentiment} | ${d.keyTakeaway}`);
});

const uniqueCompetitors = [...new Set(allCompetitors)].join(', ') || 'None mentioned';

const slackMessage = `*Weekly Sales Call Intelligence Report*
*${config.companyName} | ${config.weekStart} to ${config.weekEnd}*

*SUMMARY*
Total Calls Analyzed: ${totalCalls}
Positive Calls: ${positiveCallCount}
Calls with Objections: ${allObjections.length}
Calls with Buying Signals: ${allBuyingSignals.length}
Competitors Mentioned: ${uniqueCompetitors}

*TOP OBJECTIONS THIS WEEK*
${allObjections.slice(0, 3).join('\n') || 'No objections recorded this week'}

*TOP BUYING SIGNALS*
${allBuyingSignals.slice(0, 3).join('\n') || 'No buying signals recorded this week'}

*CALL BY CALL OVERVIEW*
${callSummaries.join('\n')}

_Full analysis logged to Google Sheets_`;

return [{
  json: {
    slackMessage,
    slackChannel: config.slackChannel
  }
}];
